七、完整範例：一段整潔的資料整理流程
library(tidyverse)
library(here)
set.seed(42)

RAW  &lt;- here("data", "raw")
PROC &lt;- here("data", "processed")

# ── 載入並整理捐贈國資料 ─────────────────────────
donors &lt;- read_csv(file.path(RAW, "patent_total_donors.csv"),
                   show_col_types = FALSE) |&gt;
  filter(iso3 %in% c("JPN", "KOR", "HKG", "SGP")) |&gt;  # 選目標國家
  mutate(
    year    = as.integer(year),
    patents = as.numeric(total)
  ) |&gt;
  select(iso3, year, patents) |&gt;
  filter(year &gt;= 2000, year &lt;= 2023)

# ── 載入台灣資料（手動填入）──────────────────────
taiwan &lt;- read_csv(file.path(RAW, "taiwan_patents_MANUAL.csv"),
                   comment = "#",
                   show_col_types = FALSE) |&gt;
  mutate(year = as.integer(year), patents = as.numeric(value)) |&gt;
  select(iso3, year, patents)

# ── 合併並儲存 ────────────────────────────────────
bind_rows(donors, taiwan) |&gt;
  arrange(iso3, year) |&gt;
  mutate(log_patents = log(patents)) |&gt;
  write_csv(file.path(PROC, "panel.csv"))
